ALLOWED_DOMAINS = os.environ.get('ALLOWED_REDIRECT_DOMAINS', '').split(',')  # Comma-separated domains
DEFAULT_REDIRECT_URI = os.environ.get('DEFAULT_REDIRECT_URI')

def validate_redirect_uri(redirect_uri):
    """Validate that redirect_uri is from an allowed domain"""
    if not redirect_uri:
        return False
    
    parsed_uri = urlparse(redirect_uri)
    if not parsed_uri.scheme or not parsed_uri.netloc:
        return False
    
    # Check if any allowed domain is contained in the redirect_uri
    for domain in ALLOWED_DOMAINS:
        if domain.strip() and domain.strip() in redirect_uri:
            return True
    
    return False

def get_authorization_url(redirect_uri):
    """Generate authorization URL with proper parameters"""
    if not validate_redirect_uri(redirect_uri):
        raise ValueError("Invalid redirect URI")
    
    state = secrets.token_urlsafe(32)
    session['oauth_state'] = state
    
    params = {
        'response_type': 'code',
        'client_id': CLIENT_ID,
        'redirect_uri': redirect_uri,
        'state': state,
        'scope': 'openid profile email'
    }
    
    query_string = urllib.parse.urlencode(params)
    return f"{AUTHORIZATION_ENDPOINT}?{query_string}"

